	cmd := &cobra.Command{
		Use:   "auth",
		Short: "Manage authentication for Spotify Web",
		RunE:  parentNoSubcommandRunE(flags),
	}

	cmd.AddCommand(newAuthSetupCmd(flags))
	cmd.AddCommand(newAuthLoginCmd(flags))
